 6→import net.java.ao.DBParam;
 7→
 8→import javax.inject.Inject;
 9→import javax.inject.Named;
10→
11→@Named
12→public class SequenceGeneratorMapper {
13→    @ComponentImport
14→    private final ActiveObjects ao;
15→
16→    @Inject
17→    public SequenceGeneratorMapper(ActiveObjects ao) {
18→        this.ao = ao;
19→    }
20→
21→    /**
22→     * 获取下一个全局唯一ID（从1000开始）
23→     */
24→    public int getNextId() {
25→        return ao.executeInTransaction(() -> {
26→            SequenceGenerator[] rows = ao.find(SequenceGenerator.class);
27→            SequenceGenerator row;
28→            if (rows.length == 0) {
29→                row = ao.create(SequenceGenerator.class, new DBParam("COUNTER", 999));
30→            } else {
31→                row = rows[0];
32→            }
33→            int next = row.getCounter() + 1;
34→            row.setCounter(next);
35→            row.save();
36→            return next;
37→        });
38→    }
39→}

