263→    private TemplateGroupVo updateTemplateGroup(HttpServletRequest request) throws Exception {
264→        UserProfile user = userManager.getRemoteUser(request);
265→        if (user == null) throw new RuntimeException("未登录");
266→
267→        TemplateGroupUpdateRo ro = readJsonBody(request, TemplateGroupUpdateRo.class);
268→        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
269→        if (ro.getName() == null || ro.getName().trim().isEmpty()) throw new RuntimeException("名称不能为空");
270→        TemplateGroup updated = templateGroupMapper.update(ro.getId(), ro.getName().trim());
271→        if (updated == null) throw new RuntimeException("记录不存在");
272→        return TemplateGroupVo.from(updated);
273→    }
