279→        TemplateGroupDeleteRo ro = readJsonBody(request, TemplateGroupDeleteRo.class);
280→        if (ro == null || ro.getId() <= 0) throw new RuntimeException("非法ID");
281→        boolean success = templateGroupMapper.deleteById(ro.getId());
