372→            Object item = arr.get(i);
373→            if (!(item instanceof JSONObject)) throw new RuntimeException("issues项必须为对象");
374→            issueRos.add(CreateJiraIssueV2Ro.parseCreateJiraIssueV2((JSONObject) item));
